const stdout = $json.stdout || "";

let parsed;

try {
  parsed = JSON.parse(stdout);
} catch (e) {
  throw new Error("No se pudo parsear stdout del build_question_rag_context.py: " + stdout);
}

if (!parsed.batches || !Array.isArray(parsed.batches)) {
  throw new Error("No se encontraron batches en la salida: " + stdout);
}

return parsed.batches.map(batch => ({
  json: {
    case_id: parsed.case_id,
    batch_id: batch.batch_id,
    batch_path: batch.path,
    question_count: batch.question_count,
    unit_count: batch.unit_count
  }
}));

const stdout = $json.stdout || "";
let batchData;

try {
  batchData = JSON.parse(stdout);
} catch (e) {
  batchData = $json;
}

if (!batchData || !batchData.batch_id) {
  throw new Error("No se recibió un batch válido para el agente RAG.");
}

/*
  IMPORTANTE:
  Este nombre debe coincidir EXACTAMENTE con el nombre de la tool en n8n.
  Si renombraras el nodo/tool, cambia este valor.
*/
const RAG_TOOL_NAME = "risk_catalog_search";
const RAG_COLLECTION_EXPECTED = "tfm_rag_manual_agent";

function firstNonEmpty(...values) {
  for (const value of values) {
    if (value === null || value === undefined) continue;

    const text = String(value).trim();

    if (text && text !== "undefined" && text !== "null" && text !== "#N/A") {
      return text;
    }
  }

  return "";
}

function getNested(obj, path) {
  try {
    return path.split(".").reduce((acc, key) => acc?.[key], obj);
  } catch (e) {
    return "";
  }
}

function normalizeKey(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

function normalizeQid(value) {
  const text = String(value || "").toUpperCase().trim();
  const match = text.match(/Q[\s_\-]?(\d{1,3})/i) || text.match(/(\d{1,3})/);

  if (!match) return "";

  const num = match[1] || match[0];

  return `Q_${String(Number(num)).padStart(3, "0")}`;
}

function findDeepValue(obj, keyCandidates) {
  if (!obj || typeof obj !== "object") return "";

  const normalizedCandidates = keyCandidates.map(normalizeKey);
  const stack = [obj];

  while (stack.length) {
    const current = stack.pop();

    if (!current || typeof current !== "object") continue;

    for (const [key, value] of Object.entries(current)) {
      const normalizedKey = normalizeKey(key);

      if (normalizedCandidates.includes(normalizedKey)) {
        const text = firstNonEmpty(value);
        if (text) return text;
      }

      if (value && typeof value === "object") {
        stack.push(value);
      }
    }
  }

  return "";
}

function extractProviderAnswer(q) {
  return firstNonEmpty(
    q.provider_answer,
    q.answer,
    q.response,
    q.respuesta,
    q.valor,
    q.value,
    q.selected_answer,
    q.selectedOption,
    q.raw_answer,
    q.rawResponse,
    q["Respuesta"],
    q["respuesta"],
    getNested(q, "provider.answer"),
    getNested(q, "provider.response"),
    getNested(q, "answer.value"),
    getNested(q, "answer.response"),
    findDeepValue(q, [
      "provider_answer",
      "answer",
      "respuesta",
      "response",
      "valor",
      "value",
      "selected_answer",
      "raw_answer"
    ])
  );
}

function extractProviderDetails(q) {
  return firstNonEmpty(
    q.provider_details,
    q.provider_explanation,
    q.answer_explanation,
    q.response_explanation,
    q.explanation,
    q.explicacion,
    q.detalle,
    q.details,
    q.comment,
    q.comments,
    q.observations,
    q.observaciones,
    q.justification,
    q.justificacion,
    q.evidence,
    q.evidencia,
    q.additional_info,
    q.additional_information,
    q.informacion_adicional,
    q["Explicación"],
    q["Explicacion"],
    q["explicación"],
    q["explicacion"],
    q["Observaciones"],
    q["observaciones"],
    q["Comentarios"],
    q["comentarios"],
    getNested(q, "provider.details"),
    getNested(q, "provider.explanation"),
    getNested(q, "provider.observations"),
    getNested(q, "answer.explanation"),
    getNested(q, "answer.details"),
    getNested(q, "raw.explanation"),
    getNested(q, "raw.details"),
    getNested(q, "raw.observations"),
    findDeepValue(q, [
      "provider_details",
      "provider_explanation",
      "answer_explanation",
      "response_explanation",
      "explanation",
      "explicacion",
      "detalle",
      "details",
      "comment",
      "comments",
      "observations",
      "observaciones",
      "justification",
      "justificacion",
      "evidence",
      "evidencia",
      "additional_info",
      "additional_information",
      "informacion_adicional"
    ])
  );
}

function getQuestionsFromBatchData(batchData) {
  const questions = [];

  const units =
    batchData.evaluation_units ||
    batchData.units ||
    batchData.evaluationGroups ||
    [];

  for (const unit of units) {
    const unitQuestions =
      unit.questions ||
      unit.items ||
      unit.evaluation_questions ||
      [];

    for (const q of unitQuestions) {
      questions.push(q);
    }
  }

  const rootQuestions =
    batchData.questions ||
    batchData.question_items ||
    batchData.questions_to_analyze ||
    [];

  for (const q of rootQuestions) {
    questions.push(q);
  }

  return questions;
}

function extractQuestionText(q) {
  return firstNonEmpty(
    q.question_text,
    q.question,
    q.text,
    q.title,
    q.requisito,
    q.catalog_entry?.question_text,
    q.catalog_entry?.question,
    q.catalog_entry?.text,
    q.catalog_entry?.requisito,
    q.catalog?.question_text,
    q.catalog?.question,
    q.catalog?.text,
    q.payload?.question_text,
    q.payload?.question,
    findDeepValue(q, [
      "question_text",
      "question",
      "texto_pregunta",
      "pregunta",
      "requisito"
    ])
  );
}

const batchQuestions = getQuestionsFromBatchData(batchData);

const questionsMap = new Map();

for (const q of batchQuestions) {
  const rawQid = firstNonEmpty(
    q.question_id,
    q.id,
    q.code,
    q.question_code,
    q.logical_id,
    q.catalog_entry?.question_id,
    q.payload?.question_id
  );

  const qid = normalizeQid(rawQid);

  if (!qid) continue;

  // Evitamos duplicados como Q_001 repetida dos veces.
  if (questionsMap.has(qid)) {
    continue;
  }

  const providerAnswer = extractProviderAnswer(q);
  const providerDetails = extractProviderDetails(q);
  const questionText = extractQuestionText(q);

  const exactToken = `EXACT_QUESTION_ID_${qid}`;

  /*
    La query empieza SIEMPRE por el token exacto y el question_id.
    Esto ayuda a que Qdrant recupere la ficha correcta.
  */
  const ragSearchQuery = `${exactToken} ${qid} ${questionText}`.trim();

  questionsMap.set(qid, {
    question_id: qid,
    exact_rag_token: exactToken,

    /*
      Este es el valor que el agente debe pasar literalmente a la tool.
    */
    tool_input: ragSearchQuery,
    rag_search_query: ragSearchQuery,

    question_text: questionText,
    provider_answer: providerAnswer,
    provider_explanation: providerDetails,
    provider_combined_response: [
      providerAnswer ? `Respuesta: ${providerAnswer}` : "",
      providerDetails ? `Explicación: ${providerDetails}` : ""
    ].filter(Boolean).join("\n"),

    /*
      Campos explícitos para reforzar al agente.
    */
    tool_required: true,
    required_tool_name: RAG_TOOL_NAME,
    tool_call_instruction: `Llama a ${RAG_TOOL_NAME} con este input exacto antes de evaluar: ${ragSearchQuery}`
  });
}

const questionsForAgent = Array.from(questionsMap.values());

if (questionsForAgent.length === 0) {
  throw new Error(
    "No se encontraron preguntas dentro del batch para construir el prompt RAG TOOL. Batch recibido: " +
    JSON.stringify(batchData).slice(0, 2000)
  );
}

const requiredToolCalls = questionsForAgent.map((q, index) => ({
  order: index + 1,
  question_id: q.question_id,
  tool_name: RAG_TOOL_NAME,
  input: q.tool_input
}));

const toolCallPlanText = requiredToolCalls
  .map(call => `${call.order}. ${call.tool_name} con input: "${call.input}"`)
  .join("\n");

const systemPrompt = `
INSTRUCCIÓN PRIORITARIA ABSOLUTA:
Esta es una tarea TOOL-FIRST.

Tu primera acción obligatoria NO es responder.
Tu primera acción obligatoria es llamar a la herramienta ${RAG_TOOL_NAME}.

No puedes evaluar ninguna pregunta antes de usar la herramienta ${RAG_TOOL_NAME}.
No puedes devolver el JSON final antes de haber usado la herramienta ${RAG_TOOL_NAME}.
No puedes responder usando conocimiento general, memoria o inferencias sin RAG.

Si tienes una pregunta, debes hacer exactamente este ciclo:
1. Llamar a ${RAG_TOOL_NAME}.
2. Leer la ficha recuperada.
3. Comprobar que metadata.question_id coincide con question_id.
4. Evaluar la respuesta del proveedor.
5. Devolver JSON final.

Eres un agente experto en análisis de riesgos técnicos de ciberseguridad para soluciones SaaS.

HERRAMIENTA DISPONIBLE:
Nombre exacto de la herramienta:
${RAG_TOOL_NAME}

Uso de la herramienta:
- La herramienta recupera la ficha oficial del catálogo de riesgos.
- La herramienta debe usarse antes de evaluar cada pregunta.
- La herramienta recibe un único input textual.
- Ese input debe ser exactamente el valor tool_input de la pregunta.
- No cambies, resumas ni reformules tool_input.
- No llames a la herramienta con otro texto diferente.

CONTRATO DE USO RAG:
- Debes realizar una llamada independiente a ${RAG_TOOL_NAME} por cada question_id.
- Si hay 1 pregunta, debes hacer 1 llamada.
- Si hay 3 preguntas, debes hacer 3 llamadas.
- Si no usas la herramienta para una pregunta, la evaluación de esa pregunta es inválida.
- Si la herramienta no devuelve ficha válida, score = 2 y requires_provider_followup = true.
- Si metadata.question_id no coincide exactamente con question_id, descarta la ficha y usa score = 2.
- No uses documentos de otra pregunta.
- No inventes reglas que no estén en la ficha recuperada.

QUÉ CONTIENE LA FICHA RAG:
- reglas de scoring
- controles asociados
- incumplimientos
- condiciones de cumplimiento
- condiciones de ambigüedad
- reglas condicionales
- severidad
- mitigación

SCORES:
- score = 1: incumplimiento claro.
- score = 2: respuesta parcial, ambigua, contradictoria o evidencia insuficiente.
- score = 3: cumplimiento claro.

CRITERIOS DE DECISIÓN:
- Si la respuesta del proveedor confirma claramente el control y aporta detalle suficiente, score = 3.
- Si la respuesta del proveedor es negativa o evidencia incumplimiento claro, score = 1.
- Si falta evidencia, detalle técnico, alcance, configuración, periodicidad, cobertura, valores concretos o confirmación suficiente, score = 2.
- Si la respuesta es contradictoria, score = 2.
- Si la respuesta está vacía, score = 2.
- Si la ficha RAG no coincide con el question_id, score = 2.
- Nunca uses score = 0.

FOLLOW-UP:
- Si score = 2, requires_provider_followup = true.
- Si score = 1 o score = 3, requires_provider_followup = false.
- followup_questions debe ser siempre un array de strings.
- Si score = 2, incluye una pregunta breve y concreta para el proveedor.

NO RELLENAR:
No rellenes estos campos:
- risk_id
- risk_name
- control_ids
- amenazas
- mitigaciones
- level
- sources
- generates_finding

El sistema posterior rellenará esos campos de forma determinista usando el catálogo.

FORMATO DE RESPUESTA FINAL:
Después de usar la herramienta, devuelve únicamente JSON válido.
No uses Markdown.
No uses bloques de código.
No escribas explicación fuera del JSON.
El primer carácter de la respuesta final debe ser {.
El último carácter de la respuesta final debe ser }.

CONCISIÓN:
- answer_summary máximo 25 palabras.
- decision_reason máximo 40 palabras.
- No copies párrafos largos de la ficha RAG.
- Resume la decisión de forma breve.
`;

const userPrompt = `
ANTES DE RESPONDER, DEBES USAR LA HERRAMIENTA.

PLAN OBLIGATORIO DE LLAMADAS A TOOL:
${toolCallPlanText}

REGLA CRÍTICA:
No generes la respuesta JSON final hasta haber ejecutado todas las llamadas anteriores.

Analiza SOLO las preguntas incluidas en este batch.

CASE_ID:
${batchData.case_id}

BATCH_ID:
${batchData.batch_id}

AUTH_CONTEXT:
${JSON.stringify(batchData.auth_context || {}, null, 2)}

PREGUNTAS:
${JSON.stringify(questionsForAgent, null, 2)}

PROCEDIMIENTO OBLIGATORIO POR CADA PREGUNTA:
1. Lee question_id.
2. Lee tool_input.
3. Llama a ${RAG_TOOL_NAME} usando exactamente el valor de tool_input.
4. Comprueba que la ficha recuperada tiene metadata.question_id igual al question_id.
5. Evalúa provider_answer y provider_explanation conjuntamente.
6. Devuelve una evaluación para esa pregunta.

ESTRUCTURA OBLIGATORIA DE RESPUESTA FINAL:
{
  "batch_id": "${batchData.batch_id}",
  "case_id": "${batchData.case_id}",
  "question_evaluations": [
    {
      "question_id": "",
      "score": 1,
      "score_type": "non_compliance|partial_compliance|insufficient_evidence|ambiguous_answer|compliant",
      "answer_summary": "",
      "decision_reason": "",
      "requires_provider_followup": false,
      "followup_questions": []
    }
  ],
  "batch_validation_notes": []
}

REGLAS FINALES:
- Devuelve una evaluación por cada pregunta de PREGUNTAS.
- No devuelvas preguntas que no estén en PREGUNTAS.
- No repitas question_id.
- No uses score = 0.
- Si la ficha recuperada tiene metadata.question_id distinto del question_id evaluado, score = 2.
- No rellenes risk_id, risk_name, control_ids, amenazas, mitigaciones, level, sources ni generates_finding.
- followup_questions debe ser array de strings.
- Devuelve solo JSON válido.
`;

const batchDataB64 = Buffer.from(
  JSON.stringify(batchData),
  "utf8"
).toString("base64");

return {
  json: {
    batch_id: batchData.batch_id,
    case_id: batchData.case_id,

    batch_data: batchData,
    batch_data_b64: batchDataB64,

    questions_for_agent: questionsForAgent,
    required_tool_calls: requiredToolCalls,

    case_meta: batchData.case_meta || {},
    auth_context: batchData.auth_context || {},

    system_prompt: systemPrompt,
    user_prompt: userPrompt,

    rag_mode: "agent_tool_qdrant_vector_store",
    rag_tool_name: RAG_TOOL_NAME,
    rag_collection_expected: RAG_COLLECTION_EXPECTED,

    /*
      Campos útiles para validar después del AI Agent.
      Activa Return Intermediate Steps en el AI Agent y revisa si se han ejecutado.
    */
    expected_tool_call_count: requiredToolCalls.length,
    expected_tool_names: [RAG_TOOL_NAME],

    debug_questions_found: questionsForAgent.map(q => q.question_id),
    debug_rag_queries: questionsForAgent.map(q => q.tool_input),
    debug_required_tool_calls: requiredToolCalls,
    debug_deduplicated_question_count: questionsForAgent.length
  }
};

function getRawModelOutput(itemJson) {
  let raw =
    itemJson.output ||
    itemJson.text ||
    itemJson.response ||
    itemJson.result ||
    itemJson.message ||
    "";

  if (typeof raw !== "string") {
    raw = JSON.stringify(raw);
  }

  return raw.trim();
}

function extractJsonObject(raw) {
  raw = raw
    .replace(/^```json/i, "")
    .replace(/^```/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(raw);
  } catch (e) {}

  const firstBrace = raw.indexOf("{");
  const lastBrace = raw.lastIndexOf("}");

  if (firstBrace === -1 || lastBrace === -1 || lastBrace <= firstBrace) {
    throw new Error("No se encontró ningún objeto JSON en la respuesta del modelo. Respuesta: " + raw);
  }

  const candidate = raw.slice(firstBrace, lastBrace + 1).trim();

  try {
    return JSON.parse(candidate);
  } catch (e) {
    throw new Error("Se encontró un bloque JSON, pero no era JSON válido. Bloque: " + candidate);
  }
}

function normalizeText(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

function safeArray(value) {
  if (Array.isArray(value)) return value;
  if (!value) return [];

  if (typeof value === "string") {
    return value
      .split(/[,;\n]+/)
      .map(x => x.trim())
      .filter(Boolean);
  }

  return [];
}

function isPositiveAnswer(value) {
  const v = normalizeText(value);

  return (
    v === "si" ||
    v === "sí" ||
    v === "yes" ||
    v === "true" ||
    v.startsWith("si ") ||
    v.startsWith("sí ") ||
    v.includes("si,") ||
    v.includes("sí,") ||
    v.includes("se soporta") ||
    v.includes("soporta") ||
    v.includes("existe") ||
    v.includes("dispone") ||
    v.includes("implementado") ||
    v.includes("implantado") ||
    v.includes("habilitado") ||
    v.includes("dentro de la ue") ||
    v.includes("dentro de la union europea") ||
    v.includes("pertenecen a la union europea")
  );
}

function isNegativeAnswer(value) {
  const v = normalizeText(value);

  return (
    v === "no" ||
    v === "false" ||
    v.startsWith("no ") ||
    v.includes("no dispone") ||
    v.includes("no existe") ||
    v.includes("no soporta") ||
    v.includes("no se soporta") ||
    v.includes("no se utiliza") ||
    v.includes("no implementa") ||
    v.includes("no se accede") ||
    v.includes("no accede") ||
    v.includes("no hay acceso") ||
    v.includes("no esta habilitado") ||
    v.includes("no está habilitado")
  );
}

function classifyInfoLevel(value) {
  const v = normalizeText(value);

  if (v.includes("altamente confidencial")) return "ALTAMENTE_CONFIDENCIAL";
  if (v.includes("confidencial")) return "CONFIDENCIAL";
  if (v.includes("uso interno") || v.includes("interna") || v.includes("interno")) return "USO_INTERNO";
  if (v.includes("public")) return "PUBLICA";

  return "DESCONOCIDA";
}

function mitigationTime(level) {
  if (level === "ALTO") return "3 meses";
  if (level === "MEDIO") return "12 meses";
  if (level === "BAJO") return "Pte.";
  return "";
}

function resolveSeverityByTier(catalog, tier) {
  const t = String(tier || "").replace("TIER", "").trim();

  const sev =
    catalog?.severity_by_tier?.[`TIER ${t}`] ||
    catalog?.severity_by_tier?.[`Tier ${t}`] ||
    catalog?.severity_by_tier?.[t] ||
    "";

  const normalized = String(sev || "").toUpperCase();

  if (!normalized || ["NO DEFINIDO", "N/A", "#N/A", "INFO", "NINGUNO", "SIN RIESGO"].includes(normalized)) {
    return "";
  }

  return normalized;
}

function objectText(obj) {
  try {
    return normalizeText(JSON.stringify(obj || {}));
  } catch (e) {
    return "";
  }
}

function caseHasPersonalData(batchData, caseMeta) {
  const text = objectText({ batchData, caseMeta });

  const signals = [
    "datos personales",
    "dato personal",
    "personal data",
    "gdpr",
    "rgpd",
    "reglamento general de proteccion de datos",
    "tratamiento de datos personales"
  ];

  return signals.some(signal => text.includes(normalizeText(signal)));
}

function answerDoesNotGuaranteeGdpr(ev, qInput) {
  const rawAnswer = normalizeText(qInput?.provider_answer || "");

  if (rawAnswer === "no") return true;
  if (!rawAnswer) return true;

  const text = normalizeText([
    qInput?.provider_answer,
    qInput?.provider_details,
    qInput?.provider_combined_response,
    ev.answer_summary,
    ev.decision_reason
  ].join(" "));

  const negativeSignals = [
    "no",
    "no cumple",
    "no se garantiza",
    "no garantiza",
    "no existen",
    "no dispone",
    "sin evidencia",
    "no aporta evidencia"
  ];

  const positiveSignals = [
    "si",
    "sí",
    "cumple",
    "garantiza",
    "garantizan",
    "controles internos",
    "auditorias internas",
    "auditoría interna",
    "gdpr",
    "rgpd"
  ];

  const hasNegative = negativeSignals.some(signal => text.includes(normalizeText(signal)));
  const hasPositive = positiveSignals.some(signal => text.includes(normalizeText(signal)));

  return hasNegative && !hasPositive;
}

function resolveConditionalSeverity(ev, payload, batchData, caseMeta, qInput) {
  const qid = ev.question_id;

  if (qid === "Q_001") {
    const hasPersonalData = caseHasPersonalData(batchData, caseMeta);
    const notGdprGuaranteed = answerDoesNotGuaranteeGdpr(ev, qInput);

    if (hasPersonalData && notGdprGuaranteed && (ev.score === 1 || ev.score === 2)) {
      ev.decision_reason = "Se aplica la observación del catálogo: al existir datos personales y no garantizarse el cumplimiento GDPR, el riesgo se eleva automáticamente a ALTO.";
      ev.validation_warning = "Severidad ajustada por observación del catálogo Q_001: datos personales + GDPR no garantizado = ALTO.";
      return "ALTO";
    }

    if (!hasPersonalData && notGdprGuaranteed && (ev.score === 1 || ev.score === 2)) {
      ev.requires_human_review = true;
      ev.validation_warning = "Q_001 contiene regla condicional GDPR, pero no se ha podido confirmar automáticamente si hay datos personales.";
    }
  }

  return "";
}

function resolveAuthSeverity(ev, catalog, authContext) {
  if (ev.score === 3) return "SIN RIESGO";

  const qid = ev.question_id;

  const empresaUsersAccess = isPositiveAnswer(authContext?.empresa_users_access_answer);
  const federationAnswer = authContext?.federation_supported_or_used_answer || "";
  const federationEnabled = isPositiveAnswer(federationAnswer) && !isNegativeAnswer(federationAnswer);
  const infoLevel = classifyInfoLevel(authContext?.information_classification);

  if (!empresaUsersAccess) {
    return "SIN RIESGO";
  }

  if (qid === "Q_010") {
    if (ev.score === 3) return "SIN RIESGO";
    return "MEDIO";
  }

  if (federationEnabled) {
    return "SIN RIESGO";
  }

  if (qid === "Q_020") {
    if (infoLevel === "PUBLICA") return "MEDIO";
    if (["USO_INTERNO", "CONFIDENCIAL", "ALTAMENTE_CONFIDENCIAL"].includes(infoLevel)) return "ALTO";
    return "ALTO";
  }

  if (["Q_011", "Q_012", "Q_013", "Q_014", "Q_015", "Q_016", "Q_017", "Q_018", "Q_019"].includes(qid)) {
    if (["CONFIDENCIAL", "ALTAMENTE_CONFIDENCIAL"].includes(infoLevel)) return "ALTO";
    return "MEDIO";
  }

  if (qid === "Q_021") {
    return "MEDIO";
  }

  return "";
}

function resolveLoggingSeverity(ev, batchData) {
  if (ev.score === 3) return "SIN RIESGO";
  return "MEDIO";
}

function resolveQ001Score(ev, qInput) {
  if (ev.question_id !== "Q_001") {
    return { apply: false };
  }

  const answer = normalizeText(qInput?.provider_answer || "");

