function isPlaceholderOrWeakDetail(value) {
  const v = normalizeText(value);

  if (!v) return true;

  const weakSignals = [
    "detallar",
    "por especificar",
    "pendiente",
    "a consultar",
    "consultar con cliente",
    "depende",
    "otros",
    "definido por el proveedor",
    "lo gestiona el proveedor",
    "gestionado por el proveedor",
    "se puede generar",
    "por establecer"
  ];

  return weakSignals.some(signal => v.includes(normalizeText(signal)));
}

