function isInformationalCatalog(payload, qid) {
  const informationalIds = new Set([
    "Q_004",
    "Q_009",
    "Q_026",
    "Q_041",
    "Q_042",
    "Q_043",
    "Q_046",
    "Q_049",
    "Q_050",
    "Q_051",
    "Q_052",
    "Q_054",
    "Q_056"
  ]);

  if (informationalIds.has(qid)) {
    return true;
  }

  const observations = normalizeText([
    payload.raw_observations,
    ...(Array.isArray(payload.conditional_rules) ? payload.conditional_rules : [])
  ].join(" "));

  if (observations.includes("no aplica para saas")) return true;
  if (observations.includes("no aplica a saas")) return true;
  if (observations.includes("solo para soluciones internas")) return true;

  return false;
}

function shouldCorrectFalseInformational(ev, qInput, payload) {
  const qid = ev.question_id;

  if (isInformationalCatalog(payload, qid)) {
    return false;
  }

  if (ev.score !== 3) {
    return false;
  }

  const answerText = normalizeText([
    qInput?.provider_answer,
    qInput?.provider_details,
    qInput?.provider_combined_response
  ].join(" "));

  if (!answerText) {
    return true;
  }

  if (answerIsNever(answerText)) {
    return true;
  }

  if (
    answerIsNo(answerText) &&
    !["Q_003", "Q_022"].includes(qid)
  ) {
    return true;
  }

  if (
    normalizeText(ev.score_type) === "informational" &&
    !isInformationalCatalog(payload, qid)
  ) {
    return true;
  }

  return false;
}

