function getQuestionsFromBatchData(batchData) {
  const questions = [];

  const units =
    batchData?.evaluation_units ||
    batchData?.units ||
    batchData?.evaluationGroups ||
    [];

  for (const unit of units) {
    const unitQuestions =
      unit.questions ||
      unit.items ||
      unit.evaluation_questions ||
      [];

    for (const q of unitQuestions) {
      questions.push(q);
    }
  }

  const rootQuestions =
    batchData?.questions ||
    batchData?.question_items ||
    batchData?.questions_to_analyze ||
    [];

  for (const q of rootQuestions) {
    questions.push(q);
  }

  return questions;
}

function buildCatalogMapFromBatchData(batchData) {
  const map = {};
  const questions = getQuestionsFromBatchData(batchData);

  for (const q of questions) {
    const qid = String(q.question_id || q.id || q.code || "").trim().toUpperCase();
    if (!qid) continue;

    const catalog =
      q.catalog_entry ||
      q.catalog ||
      q.catalog_payload ||
      q.rag_catalog_entry ||
      null;

    if (catalog) {
      map[qid] = catalog;
    }
  }

  return map;
}

function buildQuestionInputMapFromBatchData(batchData) {
  const map = {};
  const questions = getQuestionsFromBatchData(batchData);

  for (const q of questions) {
    const qid = String(q.question_id || q.id || q.code || "").trim().toUpperCase();
    if (!qid) continue;

    map[qid] = {
      question_id: qid,
      question_text: q.question_text || q.question || q.text || "",
      provider_answer: q.provider_answer || q.answer || "",
      provider_details:
        q.provider_details ||
        q.provider_explanation ||
        q.answer_explanation ||
        q.details ||
        q.comment ||
        q.comments ||
        q.observations ||
        q.observaciones ||
        "",
      provider_combined_response: [
        q.provider_answer || q.answer ? `Respuesta: ${q.provider_answer || q.answer}` : "",
        q.provider_details || q.provider_explanation || q.answer_explanation || q.details || q.observations
          ? `Explicación: ${q.provider_details || q.provider_explanation || q.answer_explanation || q.details || q.observations}`
          : ""
      ].filter(Boolean).join("\n"),
      catalog_entry: q.catalog_entry || q.catalog || q.catalog_payload || null
    };
  }

  return map;
}

