      if (items && items[currentIndex] && items[currentIndex].json) {
        const candidate = items[currentIndex].json;
        const candidateBatchId =
          candidate.batch_id ||
          candidate.batch_data?.batch_id ||
          "";

        if (
          (candidate.batch_data || candidate.catalog_entries_by_question) &&
          (!expectedBatchId || candidateBatchId === expectedBatchId)
        ) {
          return candidate;
        }
      }

      if (expectedBatchId && items && Array.isArray(items)) {
        for (const item of items) {
          const candidate = item.json || {};
          const candidateBatchId =
            candidate.batch_id ||
            candidate.batch_data?.batch_id ||
            "";

          if (
            candidateBatchId === expectedBatchId &&
            (candidate.batch_data || candidate.catalog_entries_by_question)
          ) {
            return candidate;
          }
        }
      }

      if (items && items[0] && items[0].json) {
        const fallback = items[0].json;

        if (fallback.batch_data || fallback.catalog_entries_by_question) {
          return fallback;
        }
      }
    } catch (e) {}
  }

  return {};
}

function normalizeScoreType(scoreType, score) {
  let st = String(scoreType || "").split("|")[0].trim();

  const allowed = [
    "non_compliance",
    "partial_compliance",
    "insufficient_evidence",
    "ambiguous_answer",
    "compliant"
  ];

  if (!allowed.includes(st)) {
    if (score === 1) st = "non_compliance";
    else if (score === 2) st = "insufficient_evidence";
    else if (score === 3) st = "compliant";
    else st = "insufficient_evidence";
  }

  return st;
}

function createFallbackEvaluation(qid, qInput, reason) {
  return {
    question_id: qid,
    score: 2,
    score_type: "insufficient_evidence",
    answer_summary: "No se ha podido obtener una evaluación fiable del modelo para esta pregunta.",
    decision_reason: reason || "El modelo no devolvió una evaluación válida para esta pregunta.",
    requires_provider_followup: true,
    followup_questions: [
      "¿Podéis aportar evidencia o aclaración adicional que permita confirmar si el control está implantado y cuál es su alcance?"
    ],
    requires_human_review: true,
    provider_answer: qInput?.provider_answer || "",
    provider_details: qInput?.provider_details || ""
  };
}

const raw = getRawModelOutput($json);

let promptNodeItem = getPreviousPromptItem("");

let parsed;
let jsonParseError = null;

try {
  parsed = extractJsonObject(raw);
} catch (error) {
  jsonParseError = error.message;

  parsed = {
    batch_id: promptNodeItem.batch_id || promptNodeItem.batch_data?.batch_id || "",
    case_id: promptNodeItem.case_id || promptNodeItem.batch_data?.case_id || "",
    question_evaluations: [],
    batch_validation_notes: [
      {
        type: "model_warning",
        description: "El modelo no devolvió JSON válido. Se generará evaluación fallback para las preguntas del batch.",
        question_id: "",
        source: "normalizer_json_parse_fallback"
      }
    ]
  };
}

const expectedBatchId =
  parsed.batch_id ||
  promptNodeItem.batch_id ||
  promptNodeItem.batch_data?.batch_id ||
  "";

const promptNodeItemByBatch = getPreviousPromptItem(expectedBatchId);

if (
  promptNodeItemByBatch &&
  (promptNodeItemByBatch.batch_data || promptNodeItemByBatch.catalog_entries_by_question)
) {
  promptNodeItem = promptNodeItemByBatch;
}

const batchData = promptNodeItem.batch_data || {};
const batchId = parsed.batch_id || promptNodeItem.batch_id || batchData.batch_id || "";
const caseId = parsed.case_id || promptNodeItem.case_id || batchData.case_id || "";

let catalogByQuestion = promptNodeItem.catalog_entries_by_question || {};
let questionInputById = promptNodeItem.question_inputs_by_id || {};

if (!Object.keys(catalogByQuestion).length) {
  catalogByQuestion = buildCatalogMapFromBatchData(batchData);
}

if (!Object.keys(questionInputById).length) {
  questionInputById = buildQuestionInputMapFromBatchData(batchData);
}

const caseMeta = promptNodeItem.case_meta || batchData.case_meta || {};
const authContext = promptNodeItem.auth_context || batchData.auth_context || {};

if (!Array.isArray(parsed.question_evaluations)) {
  parsed.question_evaluations = [];
}

if (!Array.isArray(parsed.batch_validation_notes)) {
  parsed.batch_validation_notes = [];
}

const expectedQuestionIds = new Set([
  ...Object.keys(catalogByQuestion),
  ...Object.keys(questionInputById)
]);

const dedupedByQuestion = {};

for (const evRaw of parsed.question_evaluations) {
  const qid = String(evRaw.question_id || "").trim().toUpperCase();

  if (!qid) {
    parsed.batch_validation_notes.push({
      type: "model_warning",
      description: "El modelo devolvió una evaluación sin question_id. Se descarta.",
      question_id: "",
      source: "post_ai_validation"
    });
    continue;
  }

  if (!expectedQuestionIds.has(qid)) {
    parsed.batch_validation_notes.push({
      type: "model_warning",
      description: `El modelo devolvió ${qid}, pero esa pregunta no pertenece a este batch. Se descarta.`,
      question_id: qid,
      source: "post_ai_validation"
    });
    continue;
  }

  if (dedupedByQuestion[qid]) {
    const previousScore = Number(dedupedByQuestion[qid].score);
    const newScore = Number(evRaw.score);

    if (previousScore !== newScore) {
      dedupedByQuestion[qid] = {
        question_id: qid,
        score: 2,
        score_type: "ambiguous_answer",
        answer_summary: "El modelo devolvió evaluaciones duplicadas y contradictorias para esta pregunta.",
        decision_reason: "Se detectaron varios resultados para el mismo question_id con scores diferentes. Se marca como ambiguo para revisión.",
        requires_provider_followup: true,
        followup_questions: [
          "¿Podéis aclarar la respuesta y aportar evidencia suficiente para confirmar si el control aplica y está implantado?"
        ],
        requires_human_review: true
      };
    } else {
      dedupedByQuestion[qid] = evRaw;
    }

    parsed.batch_validation_notes.push({
      type: "model_warning",
      description: `El modelo duplicó la pregunta ${qid}. Se conserva una única evaluación.`,
      question_id: qid,
      source: "post_ai_validation"
    });

    continue;
  }

  dedupedByQuestion[qid] = evRaw;
}

parsed.question_evaluations = Object.values(dedupedByQuestion);

if (jsonParseError) {
  parsed.batch_validation_notes.push({
    type: "model_warning",
    description: `Error parseando JSON del modelo: ${jsonParseError}`,
    question_id: "",
    source: "normalizer_json_parse_fallback"
  });
}

for (const ev of parsed.question_evaluations) {
  ev.question_id = String(ev.question_id || "").trim().toUpperCase();

  const qInput = questionInputById[ev.question_id];
  const catalog = catalogByQuestion[ev.question_id];

  let score = Number(ev.score);
  ev.score_type = normalizeScoreType(ev.score_type, score);

  if (score === 0) {
    score = 1;
    ev.validation_warning = "El modelo devolvió score=0. Se corrige inicialmente a score=1.";
  }

  const q001Score = resolveQ001Score(ev, qInput);

  if (q001Score.apply) {
    score = q001Score.score;
    ev.score_type = q001Score.score_type;
    ev.answer_summary = q001Score.answer_summary;
    ev.decision_reason = q001Score.decision_reason;
    ev.requires_provider_followup = q001Score.requires_provider_followup;
    ev.requires_human_review = q001Score.requires_human_review;
    ev.validation_warning = "Score ajustado por regla determinista Q_001.";
  }

  const legalScore = resolveLegalScore(ev, qInput);

  if (legalScore.apply) {
    score = legalScore.score;

    if (legalScore.answer_summary) {
      ev.answer_summary = legalScore.answer_summary;
    }

    ev.decision_reason = legalScore.reason;
    ev.requires_provider_followup = score === 2;
    ev.requires_human_review = score === 2;
    ev.validation_warning = "Score ajustado por regla determinista legal Q_002/Q_003.";
  }

  const authScore = resolveAuthScore(ev, qInput, authContext);

  if (authScore.apply) {
    score = authScore.score;
    ev.score_type = authScore.score_type;
    ev.answer_summary = authScore.answer_summary;
    ev.decision_reason = authScore.decision_reason;
    ev.requires_provider_followup = authScore.requires_provider_followup;
    ev.requires_human_review = authScore.requires_human_review;
    ev.validation_warning = "Score ajustado por regla determinista de autenticación.";
  }

  const specificScore = resolveSpecificScore(ev, qInput);

  if (specificScore.apply) {
    score = specificScore.score;
    ev.score_type = specificScore.score_type;
    ev.answer_summary = specificScore.answer_summary;
    ev.decision_reason = specificScore.decision_reason;
    ev.requires_provider_followup = specificScore.requires_provider_followup;
    ev.requires_human_review = specificScore.requires_human_review;
    ev.validation_warning = "Score ajustado por regla determinista específica.";
  }

  ev.score = score;

  if (shouldConvertPositiveWithLackDetailToScore2(ev, qInput)) {
    score = 2;
    ev.score = 2;
    ev.score_type = "insufficient_evidence";
    ev.requires_provider_followup = true;
    ev.requires_human_review = true;
    ev.followup_questions = [
      "¿Podéis aportar evidencia, configuración, alcance y documentación que permita confirmar que el control está implantado correctamente?"
    ];
    ev.validation_warning = "Score ajustado: respuesta afirmativa con falta de detalle/evidencia. Se cambia a score=2.";
  }

  if (![1, 2, 3].includes(score)) {
    score = 2;
    ev.validation_error = "Score inválido devuelto por el modelo. Se ajusta a score=2.";
  }

  ev.score = score;
  ev.score_type = normalizeScoreType(ev.score_type, score);

  if (score === 1) {
    ev.score_type = "non_compliance";
    ev.generates_finding = true;
    ev.requires_provider_followup = false;
  }

  if (score === 2) {
    if (!["partial_compliance", "insufficient_evidence", "ambiguous_answer"].includes(ev.score_type)) {
      ev.score_type = "insufficient_evidence";
    }

    ev.generates_finding = true;
    ev.requires_provider_followup = true;
    ev.requires_human_review = true;

    if (!Array.isArray(ev.followup_questions) || ev.followup_questions.length === 0) {
      ev.followup_questions = [
        "¿Podéis aportar evidencia o aclaración adicional que permita confirmar si el control está implantado y cuál es su alcance?"
      ];
    }
  }

  if (score === 3) {
    ev.score_type = "compliant";
    ev.generates_finding = false;
    ev.requires_provider_followup = false;
    ev.requires_human_review = false;
    ev.followup_questions = [];
  }

  if (!catalog) {
    ev.requires_human_review = true;
    ev.validation_error = `No se encontró catalog_entry para ${ev.question_id}.`;

    parsed.batch_validation_notes.push({
      type: "manual_review",
      description: `No se encontró catalog_entry para ${ev.question_id}. Revisa que el nodo anterior exporte catalog_entries_by_question.`,
      question_id: ev.question_id,
      source: "post_ai_validation"
    });

    continue;
  }

  const payload = catalog.payload || catalog;

  if (shouldCorrectFalseInformational(ev, qInput, payload)) {
    if (answerIsNever(qInput?.provider_answer || qInput?.provider_combined_response)) {
      ev.score = 1;
      ev.score_type = "non_compliance";
      ev.answer_summary = ev.answer_summary || "La respuesta indica que la medida nunca se realiza.";
      ev.decision_reason = ev.decision_reason || "La respuesta indica ausencia del control o de la actividad requerida.";
      ev.requires_provider_followup = false;
      ev.requires_human_review = false;
      ev.validation_warning = "Score corregido: se evita tratar como informativa una pregunta no informativa con respuesta de incumplimiento.";
    } else if (answerIsNo(qInput?.provider_answer || qInput?.provider_combined_response)) {
      ev.score = 1;
      ev.score_type = "non_compliance";
      ev.answer_summary = ev.answer_summary || "La respuesta indica que el control no está implantado.";
      ev.decision_reason = ev.decision_reason || "La respuesta negativa en una pregunta no informativa implica incumplimiento del control.";
      ev.requires_provider_followup = false;
      ev.requires_human_review = false;
      ev.validation_warning = "Score corregido: respuesta negativa en pregunta no informativa.";
    } else {
      ev.score = 2;
      ev.score_type = "insufficient_evidence";
      ev.requires_provider_followup = true;
      ev.requires_human_review = true;
      ev.followup_questions = [
        "¿Podéis aportar evidencia o aclaración adicional que permita confirmar si el control está implantado y cuál es su alcance?"
      ];
      ev.validation_warning = "Score corregido: se evita tratar como informativa una pregunta no informativa.";
    }
  }

  if (isInformationalCatalog(payload, ev.question_id)) {
    ev.score = 3;
    ev.score_type = "informational";
    ev.generates_finding = false;
    ev.requires_provider_followup = false;
    ev.requires_human_review = false;
    ev.followup_questions = [];
    ev.level = "SIN RIESGO";

    forceCatalogFields(ev, catalog);

    ev.level = "SIN RIESGO";
    ev.risk_id = "";
    ev.risk_name = "";
    ev.control_ids = [];
    ev.incumplimiento_identificado = "";
    ev.controles_asociados = "";
    ev.amenazas = [];
    ev.mitigation = "";
    ev.mitigation_guide = "";
    ev.report_context_example = "";
    ev.report_detail_example = "";
    ev.tiempo_mitigacion = "";
    ev.validation_warning = "Pregunta tratada como informativa/no aplicable según catálogo.";
  } else {
    forceCatalogFields(ev, catalog);

    const evaluationGroup = payload.evaluation_group || "";

    if (ev.score === 3) {
      ev.level = "SIN RIESGO";
    } else {
      const conditionalLevel = resolveConditionalSeverity(ev, payload, batchData, caseMeta, qInput);

      if (conditionalLevel) {
        ev.level = conditionalLevel;
      }

      if (!ev.level && evaluationGroup === "AUTHENTICATION") {
        ev.level = resolveAuthSeverity(ev, payload, authContext);
      }

      if (!ev.level && evaluationGroup === "LOGGING_MONITORING") {
        ev.level = resolveLoggingSeverity(ev, batchData);
      }

      if (!ev.level) {
        ev.level = resolveSeverityByTier(payload, caseMeta.tier);
      }
    }

    if (!ev.level && ev.score !== 3) {
      ev.requires_human_review = true;
      parsed.batch_validation_notes.push({
        type: "manual_review",
        description: `No se pudo determinar la severidad para ${ev.question_id}. Revisar reglas del catálogo.`,
        question_id: ev.question_id,
        source: "post_ai_validation"
      });
    }

    ev.tiempo_mitigacion = mitigationTime(ev.level);
  }

  ev.provider_answer = qInput?.provider_answer || "";
  ev.provider_details = qInput?.provider_details || "";
}

const existingIds = new Set(parsed.question_evaluations.map(ev => ev.question_id));

for (const qid of Object.keys(catalogByQuestion)) {
  if (existingIds.has(qid)) continue;

  const qInput = questionInputById[qid];
  const catalog = catalogByQuestion[qid];
  const payload = catalog.payload || catalog;

  let ev = createFallbackEvaluation(
    qid,
    qInput,
    "La pregunta estaba incluida en el batch, pero el modelo la omitió o no devolvió una evaluación válida."
  );

  const q001Score = resolveQ001Score(ev, qInput);

  if (q001Score.apply) {
    ev.score = q001Score.score;
    ev.score_type = q001Score.score_type;
    ev.answer_summary = q001Score.answer_summary;
    ev.decision_reason = q001Score.decision_reason;
    ev.requires_provider_followup = q001Score.requires_provider_followup;
    ev.requires_human_review = q001Score.requires_human_review;
    ev.validation_warning = "Score ajustado por regla determinista Q_001 en evaluación omitida.";
  }

  const legalScore = resolveLegalScore(ev, qInput);

  if (legalScore.apply) {
    ev.score = legalScore.score;
    ev.score_type = ev.score === 3 ? "compliant" : "insufficient_evidence";
    ev.answer_summary = legalScore.answer_summary;
    ev.decision_reason = legalScore.reason;
    ev.requires_provider_followup = ev.score === 2;
    ev.requires_human_review = ev.score === 2;
    ev.validation_warning = "Score ajustado por regla determinista legal Q_002/Q_003 en evaluación omitida.";
  }

  const authScore = resolveAuthScore(ev, qInput, authContext);

  if (authScore.apply) {
    ev.score = authScore.score;
    ev.score_type = authScore.score_type;
    ev.answer_summary = authScore.answer_summary;
    ev.decision_reason = authScore.decision_reason;
    ev.requires_provider_followup = authScore.requires_provider_followup;
    ev.requires_human_review = authScore.requires_human_review;
    ev.validation_warning = "Score ajustado por regla determinista de autenticación en evaluación omitida.";
  }

  const specificScore = resolveSpecificScore(ev, qInput);

  if (specificScore.apply) {
    ev.score = specificScore.score;
    ev.score_type = specificScore.score_type;
    ev.answer_summary = specificScore.answer_summary;
    ev.decision_reason = specificScore.decision_reason;
    ev.requires_provider_followup = specificScore.requires_provider_followup;
    ev.requires_human_review = specificScore.requires_human_review;
    ev.validation_warning = "Score ajustado por regla determinista específica en evaluación omitida.";
  }

  if (isInformationalCatalog(payload, qid)) {
    ev.score = 3;
    ev.score_type = "informational";
    ev.generates_finding = false;
    ev.requires_provider_followup = false;
    ev.requires_human_review = false;
    ev.followup_questions = [];
    ev.level = "SIN RIESGO";

    forceCatalogFields(ev, catalog);

    ev.level = "SIN RIESGO";
    ev.risk_id = "";
    ev.risk_name = "";
    ev.control_ids = [];
    ev.incumplimiento_identificado = "";
    ev.controles_asociados = "";
    ev.amenazas = [];
    ev.mitigation = "";
    ev.mitigation_guide = "";
    ev.report_context_example = "";
    ev.report_detail_example = "";
    ev.tiempo_mitigacion = "";
    ev.validation_warning = "Pregunta omitida por el modelo, tratada como informativa/no aplicable según catálogo.";
  } else {
    forceCatalogFields(ev, catalog);

    const evaluationGroup = payload.evaluation_group || "";

    if (ev.score === 3) {
      ev.level = "SIN RIESGO";
    } else {
      const conditionalLevel = resolveConditionalSeverity(ev, payload, batchData, caseMeta, qInput);

      if (conditionalLevel) {
        ev.level = conditionalLevel;
      }

      if (!ev.level && evaluationGroup === "AUTHENTICATION") {
        ev.level = resolveAuthSeverity(ev, payload, authContext);
      }

      if (!ev.level && evaluationGroup === "LOGGING_MONITORING") {
        ev.level = resolveLoggingSeverity(ev, batchData);
      }

      if (!ev.level) {
        ev.level = resolveSeverityByTier(payload, caseMeta.tier);
      }
    }

    ev.tiempo_mitigacion = mitigationTime(ev.level);
  }

  parsed.question_evaluations.push(ev);

  parsed.batch_validation_notes.push({
    type: "manual_review",
    description: `El modelo omitió la evaluación de ${qid}; se ha creado evaluación automática con score=${ev.score}.`,
    question_id: qid,
    source: "post_ai_validation"
  });
}

parsed.batch_id = batchId;
parsed.case_id = caseId;

const scoringBatchB64 = Buffer.from(
  JSON.stringify(parsed, null, 2),
  "utf8"
).toString("base64");

return {
