import json
import re
from pathlib import Path
from datetime import datetime
from collections import defaultdict

case_id = "{{$json.case_id}}".strip()

if not case_id or "{{" in case_id or "}}" in case_id or case_id.lower() in {"undefined", "null", "none"}:
    case_id = ""

def load_json(path, default=None):
    path = Path(path)

    if not path.exists():
        return default

    return json.loads(path.read_text(encoding="utf-8"))

def write_json(path, data):
    path = Path(path)
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(
        json.dumps(data, ensure_ascii=False, indent=2),
        encoding="utf-8"
    )

def discover_case_id():
    root = Path("/data/cases")
    candidates = []

    if not root.exists():
        return ""

    for case_dir in root.iterdir():
        if not case_dir.is_dir():
            continue

        possible_files = [
            case_dir / "02_json" / "case_meta.json",
            case_dir / "03_analysis" / "case_status.json",
            case_dir / "03_analysis" / "report_data.json",
            case_dir / "03_analysis" / "scoring_final.json",
            case_dir / "04_report" / "report_pack.json"
        ]

        existing = [p for p in possible_files if p.exists()]

        if existing:
            latest = max(p.stat().st_mtime for p in existing)
            candidates.append((latest, case_dir.name))

    if not candidates:
        return ""

    candidates.sort(reverse=True)
    return candidates[0][1]

def norm(value):
    return str(value or "").strip()

def clean_text(value):
    text = norm(value)
    text = re.sub(r"\s+", " ", text)
    return text.strip()

def normalize_level(value):
    v = norm(value).upper()

    if "ALTO" in v:
        return "ALTO"

    if "MEDIO" in v:
        return "MEDIO"

    if "BAJO" in v:
        return "BAJO"

    return ""

LEVEL_RANK = {
    "": 0,
    "BAJO": 1,
    "MEDIO": 2,
    "ALTO": 3
}

def max_level(levels):
    result = ""

    for level in levels:
        level = normalize_level(level)

        if LEVEL_RANK.get(level, 0) > LEVEL_RANK.get(result, 0):
            result = level

    return result

def mitigation_time(level):
    level = normalize_level(level)

    if level == "ALTO":
        return "3 meses"

    if level == "MEDIO":
        return "12 meses"

    if level == "BAJO":
        return "Pte."

    return ""

def risk_color(level):
    level = normalize_level(level)

    if level == "ALTO":
        return "red"

    if level == "MEDIO":
        return "orange"

    if level == "BAJO":
        return "yellow"

    return "gray"

def unique_keep_order(values):
    out = []
    seen = set()

    for value in values:
        if isinstance(value, list):
            candidates = value
        else:
            candidates = [value]

        for candidate in candidates:
            text = clean_text(candidate)

            if not text:
                continue

            key = text.lower()

            if key not in seen:
                seen.add(key)
                out.append(text)

    return out

def as_list(value):
    if value is None:
        return []

    if isinstance(value, list):
        return value

    if isinstance(value, str):
        parts = re.split(r"[;\n]+", value)
        return [p.strip() for p in parts if p.strip()]

    return [str(value)]

def is_empty_or_pending(value):
    text = str(value or "").strip().lower()

    if not text:
        return True

    if text in {
        "n/a",
        "#n/a",
        "na",
        "null",
        "none",
        "undefined",
        "pendiente",
        "pendiente de confirmar"
    }:
        return True

    return False

def first_value(*values, fallback="Pendiente de confirmar"):
    for value in values:
        if isinstance(value, list):
            value = ", ".join([str(v) for v in value if str(v).strip()])

        text = str(value or "").strip()

        if not is_empty_or_pending(text):
            return text

    return fallback

def normalize_tier(value):
    if value is None or value == "":
        return ""

    if isinstance(value, int):
        return f"TIER {value}"

    text = str(value).strip().upper()

    if not text:
        return ""

    match = re.search(r"(\d+)", text)

    if match:
        return f"TIER {match.group(1)}"

    if text.startswith("TIER"):
        return text

    return text

def discover_questionnaire_file(base):
    candidates = []

    folders = [
        base / "01_originales",
        base / "01_input",
        base / "02_json",
        base
    ]

    valid_extensions = {
        ".xlsx",
        ".xls",
        ".xlsm"
    }

    for folder in folders:
        if not folder.exists():
            continue

        for path in folder.iterdir():
            if not path.is_file():
                continue

            if path.name.startswith("~$"):
                continue

            name = path.name.lower()
            suffix = path.suffix.lower()

            if suffix in valid_extensions and any(token in name for token in ["cuestionario", "questionnaire"]):
                candidates.append(path)

    if candidates:
        candidates.sort(key=lambda p: p.stat().st_mtime, reverse=True)
        return str(candidates[0])

    originales = base / "01_originales"

    if originales.exists():
        excel_files = [
            p for p in originales.iterdir()
            if p.is_file()
            and not p.name.startswith("~$")
            and p.suffix.lower() in valid_extensions
        ]

        if excel_files:
            excel_files.sort(key=lambda p: p.stat().st_mtime, reverse=True)
            return str(excel_files[0])

    return ""

def question_text(ev):
    parts = []

    if ev.get("provider_answer"):
        parts.append(f"Respuesta: {ev.get('provider_answer')}")

    if ev.get("provider_details"):
        parts.append(f"Explicación: {ev.get('provider_details')}")

    if not parts and ev.get("answer_summary"):
        parts.append(ev.get("answer_summary"))

    return "\n".join(parts).strip()

def build_question_map(evaluations):
    qmap = {}

    for ev in evaluations:
        qid = norm(ev.get("question_id")).upper()

        if not qid:
            continue

        qmap[qid] = {
            "question_id": qid,
            "provider_answer": ev.get("provider_answer", ""),
            "provider_details": ev.get("provider_details", ""),
            "answer_summary": ev.get("answer_summary", ""),
            "decision_reason": ev.get("decision_reason", ""),
            "score": ev.get("score"),
            "score_type": ev.get("score_type"),
            "text": question_text(ev)
        }

    return qmap

