function text(value) {
  return String(value ?? "").replace(/\s+/g, " ").trim();
}

function yesNo(value) {
  if (value === true) return "sí";
  if (value === false) return "no";
  return text(value) || "no indicado";
}

function arr(value) {
  if (!value) return [];
  if (Array.isArray(value)) return value.map(v => text(v)).filter(Boolean);
  return [text(value)].filter(Boolean);
}

function truncate(value, maxLength = 900) {
  const t = text(value);

  if (t.length <= maxLength) return t;

  return t.slice(0, maxLength).trim() + "...";
}

function getQuestionFacts(items, maxItems = 18) {
  return (items || [])
    .slice(0, maxItems)
    .map(q => {
      return {
        question_id: q.question_id || "",
        score: q.score,
        score_type: q.score_type || "",
        level: q.level || "",
        provider_answer: truncate(q.provider_answer || "", 350),
