function getRawModelOutput(itemJson) {
  let raw =
    itemJson.output ||
    itemJson.text ||
    itemJson.response ||
    itemJson.result ||
    itemJson.message ||
    itemJson.data ||
    "";

  if (raw && typeof raw === "object") {
    if (raw.output) raw = raw.output;
    else if (raw.text) raw = raw.text;
    else if (raw.response) raw = raw.response;
    else if (raw.message) raw = raw.message;
    else if (raw.content) raw = raw.content;
    else raw = JSON.stringify(raw);
  }

  return String(raw || "").trim();
}

function extractJsonObject(raw) {
  raw = String(raw || "")
    .replace(/^```json/i, "")
    .replace(/^```/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(raw);
  } catch (e) {}

  const first = raw.indexOf("{");
  const last = raw.lastIndexOf("}");

  if (first === -1 || last === -1 || last <= first) {
    throw new Error("No se encontró JSON en la respuesta del agente: " + raw);
  }

  return JSON.parse(raw.slice(first, last + 1));
}

function decodeB64Json(value) {
  if (!value) return null;

  try {
    return JSON.parse(Buffer.from(String(value), "base64").toString("utf8"));
  } catch (e) {
    return null;
  }
}

function getPreviousPromptItem() {
