}

function normalizeText(value) {
  if (value === null || value === undefined) return "";

  if (typeof value === "object") {
    if (Array.isArray(value)) {
      return value
        .map(v => normalizeText(v))
        .filter(Boolean)
        .join(" ");
    }

    return Object.entries(value)
      .map(([key, val]) => {
        const cleanVal = normalizeText(val);
        if (!cleanVal) return "";
        const cleanKey = String(key || "")
          .replace(/_/g, " ")
          .trim();
        return `${cleanKey}: ${cleanVal}.`;
      })
      .filter(Boolean)
      .join(" ");
  }

  return String(value || "")
    .replace(/\s+/g, " ")
    .replace(/\s+\./g, ".")
    .replace(/\.\s*\./g, ".")
    .trim();
}

function isWeakText(value) {
  const text = normalizeText(value).toLowerCase();

  if (!text) return true;

  const weakExact = [
    "pendiente de confirmar",
    "información no aportada",
    "informacion no aportada",
    "por especificar",
    "detallar",
    "diarios",
    "diaria",
    "nunca",
    "no",
    "si",
    "sí",
    "otros"
  ];

  if (weakExact.includes(text)) return true;

  if (text.length < 55) return true;

  const wordCount = text.split(/\s+/).filter(Boolean).length;
  if (wordCount < 10) return true;

  return false;
}

