const stdout = String($json.stdout || "").trim();

function extractJson(text) {
  try {
    return JSON.parse(text);
  } catch (e) {}

  const first = text.indexOf("{");
  const last = text.lastIndexOf("}");

  if (first === -1 || last === -1 || last <= first) {
    throw new Error("No se encontró JSON válido en stdout: " + text);
  }

  return JSON.parse(text.slice(first, last + 1));
}

const parsed = extractJson(stdout);

if (!parsed.file_path) {
  throw new Error("No se recibió file_path después de copiar archivo: " + stdout);
}

return {
  json: parsed
};

const originalItems = $items("Code in JavaScript14");

const original = originalItems[$itemIndex]?.json || {};

if (!original.google_drive_project_folder_id) {
  throw new Error(
    "No se encontró google_drive_project_folder_id en Code in JavaScript14 para item " + $itemIndex
  );
}

const binary = $input.item.binary || {};

return {
  json: {
    ...original
  },
  binary
};

function extractJsonObject(value) {
  if (value && typeof value === "object") {
    return value;
  }

  const raw = String(value || "").trim();

  if (!raw) {
    throw new Error("Respuesta vacía del AI Agent RAG.");
  }

  let cleaned = raw
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    // seguimos
  }

  const first = cleaned.indexOf("{");
  const last = cleaned.lastIndexOf("}");

  if (first === -1 || last === -1 || last <= first) {
    throw new Error(
      "No se encontró JSON en la salida del AI Agent RAG: " +
      cleaned.slice(0, 1500)
    );
  }

  const candidate = cleaned.slice(first, last + 1);

  try {
    return JSON.parse(candidate);
  } catch (e) {
    throw new Error(
      "No se pudo parsear JSON del AI Agent RAG. Error: " +
      e.message +
      "\nRespuesta parcial:\n" +
      candidate.slice(0, 2500)
    );
  }
}

function getAgentOutput(json) {
  return (
    json.output ||
    json.text ||
    json.response ||
    json.ai_response ||
    json.result ||
    json.message ||
    json.data ||
    ""
  );
}

let promptItem = {};

try {
  const items = $items("Code - Construir prompt scoring RAG TOOL");
  promptItem = items[$itemIndex]?.json || {};
} catch (e) {
  promptItem = {};
}

if (!promptItem.case_id && $json.case_id) {
  promptItem = $json;
}

const agentOutput = getAgentOutput($json);
const parsed = extractJsonObject(agentOutput);

return {
  json: {
    ...promptItem,

    agent_raw_response: $json,
    agent_output_raw: typeof agentOutput === "string" ? agentOutput : JSON.stringify(agentOutput),

    output: JSON.stringify(parsed),
    text: JSON.stringify(parsed),
    response: JSON.stringify(parsed),
    ai_response: JSON.stringify(parsed),

    rag_mode: "agent_tool_qdrant",
    parsed_agent_response: parsed
  }
};
